Path('logs').mkdir(parents=True, exist_ok=True)

for name in test_names:
  clean_name = name.replace('/', '_')
  args = [
    sys.argv[1],
    "--gtest_output=xml:logs/" + clean_name + ".xml",
    "--gtest_filter=" + name
  ]
  print(f"Running {name}: {args} ...", flush=True)

  p = subprocess.Popen(
    args,
    text=True,
    universal_newlines=True,
    stdout=subprocess.PIPE,
    stderr=subprocess.STDOUT,
    shell=False,
  )

  with (Path('logs') / f"{clean_name}.log").open('w') as strm:
    for line in p.stdout:
      strm.write(line)
    strm.flush()

  p.stdout.close()
  returncode = p.wait()

  print(f"Test {name} exited with code {returncode}.", flush=True)

sys.exit(0)
